10: enum GameMode {
11:   practice,
12:   quiz,
13:   challenge,
14:   timed,
15:   endless,
16: }
17: 
18: class GameService {
19:   final GameRepository _gameRepository;
20:   final ProgressRepository _progressRepository;
21:   final StatisticsRepository _statisticsRepository;
22: 
23:   GameService({
24:     required GameRepository gameRepository,
25:     required ProgressRepository progressRepository,
26:     required StatisticsRepository statisticsRepository,
27:   })  : _gameRepository = gameRepository,
28:         _progressRepository = progressRepository,
29:         _statisticsRepository = statisticsRepository;
30: 
31:   // ── Question Loading ──
32: 
33:   Future<List<GameQuestionModel>> loadQuestions({
34:     String? tenseType,
35:     String? difficulty,
36:     GameMode? mode,
37:     int? limit,
38:   }) async {
39:     List<GameQuestionModel> questions;
40: 
41:     // Try cache first, then JSON, then Firestore
42:     questions = _gameRepository.getCachedQuestions();
43:     if (questions.isEmpty) {
44:       try {
45:         questions = await _gameRepository.loadFromJson();
46:       } catch (_) {
47:         questions = await _gameRepository.fetchFromFirestore();
48:       }
49:       await _gameRepository.cacheQuestions(questions);
50:     }
51: 
52:     // Map the game "mode" to a difficulty so it selects the right questions:
53:     //   challenge → hard
54:     // Other modes (practice/quiz/timed/endless) impose no difficulty filter.
55:     // GameMode must NOT be compared against q.mode — q.mode stores the question
56:     // content type (fill_blank, choose_tense, ...), not the play mode.
57:     final effectiveDifficulty = difficulty ??
58:         (mode == GameMode.challenge ? 'hard' : null);
59: 
60:     // Apply filters
61:     if (tenseType != null && tenseType.isNotEmpty) {
62:       if (_isSpecialCategory(tenseType)) {
63:         // "comparison" / "special_usage" are cross-tense categories — they
64:         // deliberately mix questions from every tense rather than filtering
65:         // to one. No tenseType filter is applied here.
66:       } else {
67:         // Normalise so a snake_case id (e.g. "present_indefinite") still
68:         // matches questions whose tenseType is the readable label
69:         // ("Present Indefinite").
70:         final canonical = TenseConstants.nameFromId(tenseType);
71:         final id = TenseConstants.idFromName(tenseType);
72:         questions = questions.where((q) {
73:           final qt = q.tenseType;
74:           return qt == tenseType || qt == canonical || qt == id;
75:         }).toList();
76:       }
77:     }
78:     if (effectiveDifficulty != null && effectiveDifficulty.isNotEmpty) {
79:       questions = questions.where((q) => q.difficulty == effectiveDifficulty).toList();
80:     }
81: 
82:     // Shuffle questions themselves
83:     questions.shuffle();
84: 
85:     // Shuffle options within each question so the correct answer
86:     // appears at a different position every time.
87:     final rng = Random();
88:     questions = questions.map((q) => _shuffleOptions(q, rng)).toList();
89: 
90:     if (limit != null && limit > 0 && limit < questions.length) {
91:       questions = questions.take(limit).toList();
92:     }
93: 
94:     return questions;
95:   }
96: 
97:   /// Returns a copy of [question] whose [options] (and [optionBangla])
98:   /// have been shuffled together, with [correctAnswer] updated to match
99:   /// the new position of the original correct option.
100:   GameQuestionModel _shuffleOptions(GameQuestionModel question, Random rng) {
101:     final opts = question.options;
102:     if (opts.length <= 1) return question;
103: 
104:     // Build index list [0, 1, 2, …] and shuffle it.
105:     final indices = List<int>.generate(opts.length, (i) => i)..shuffle(rng);
106: 
107:     final shuffledOptions = indices.map((i) => opts[i]).toList();
108:     final shuffledBangla = question.optionBangla.isNotEmpty
109:         ? indices.map((i) => i < question.optionBangla.length ? question.optionBangla[i] : '').toList()
110:         : <String>[];
111: 
112:     // Find where the original correct answer landed.
113:     final newCorrect = question.correctAnswer.trim().toLowerCase();
114:     int newCorrectIdx = 0;
115:     for (int i = 0; i < shuffledOptions.length; i++) {
116:       if (shuffledOptions[i].trim().toLowerCase() == newCorrect) {
117:         newCorrectIdx = i;
118:         break;
119:       }
120:     }
121: 
122:     return question.copyWith(
123:       options: shuffledOptions,
124:       optionBangla: shuffledBangla,
125:       correctAnswer: shuffledOptions[newCorrectIdx],
126:     );
127:   }
128: 
129:   /// Special categories that mix questions across tenses instead of filtering
130:   /// to a single tense. These have no dedicated question file.
131:   bool _isSpecialCategory(String tenseType) {
132:     const special = {'comparison', 'special_usage', 'mixed', 'all'};
133:     return special.contains(tenseType.toLowerCase());
134:   }
135: 
136:   Future<List<GameQuestionModel>> loadQuestionsByTenseType(String tenseType) {
137:     return loadQuestions(tenseType: tenseType);
138:   }
139: 
140:   Future<List<GameQuestionModel>> loadQuestionsByDifficulty(String difficulty) {
141:     return loadQuestions(difficulty: difficulty);
142:   }
143: 
144:   // ── Answer Checking ──
145: 
146:   bool checkAnswer(GameQuestionModel question, String selectedAnswer) {
147:     return question.correctAnswer.trim().toLowerCase() ==
148:         selectedAnswer.trim().toLowerCase();
149:   }
150: 
151:   // ── Game Result ──
152: 
153:   Future<GameResultModel> calculateResult({
154:     required List<GameQuestionModel> questions,
155:     required List<String> userAnswers,
156:     required int earnedXP,
157:     required int earnedCoins,
158:   }) async {
159:     int correct = 0;
160:     int wrong = 0;
161: 
162:     for (int i = 0; i < questions.length && i < userAnswers.length; i++) {
163:       if (checkAnswer(questions[i], userAnswers[i])) {
164:         correct++;
165:       } else {
166:         wrong++;
167:       }
168:     }
169: 
170:     final total = correct + wrong;
171:     final accuracy = total > 0 ? correct / total : 0.0;
172:     final score = (correct * 10) + (accuracy * 100).round();
173: 
174:     return GameResultModel(
175:       score: score,
176:       correctAnswers: correct,
177:       wrongAnswers: wrong,
178:       accuracy: accuracy,
179:       earnedXP: earnedXP,
180:       earnedCoins: earnedCoins,
181:     );
182:   }
183: 
184:   Future<void> saveResult(
185:     GameResultModel result, {
186:     Duration? duration,
187:   }) async {
188:     // Persist duration into the result so historical aggregates stay
189:     // accurate even if the caller forgets to thread it through.
190:     final resultWithDuration = duration != null && result.durationSeconds == 0
191:         ? result.copyWith(durationSeconds: duration.inSeconds)
192:         : result;
193: 
194:     await _statisticsRepository.saveResult(resultWithDuration);
195: 
196:     // Cumulative time-played counter (Phase 18).
197:     if (duration != null && duration.inSeconds > 0) {
198:       await _statisticsRepository.addTimePlayed(duration.inSeconds);
199:     }
200: 
201:     // Phase 18 win counters — derived from the result's own flags so
202:     // the same code path serves boss / daily / normal games.
203:     if (resultWithDuration.isBossWin) {
204:       await _statisticsRepository.incrementBossWins();
205:     }
206:     if (resultWithDuration.isDailyChallengeWin) {
207:       await _statisticsRepository.incrementDailyChallengeWins();
208:     }
209: 
210:     await _progressRepository.addXP(result.earnedXP);
211:     await _progressRepository.addCoins(result.earnedCoins);
212: 
213:     // ⚠️ Firebase upload removed from here to eliminate duplicate uploads.
214:     // ResultScreen._syncGameDataToFirebase() handles ALL Firebase uploads
215:     // (Hive → Firestore) for every game flow — main game, mode screens, etc.
216:     // This ensures a single source of truth: Hive → Firebase, and ALL fields
217:     // (durationSeconds, isBossWin, isDailyChallengeWin, gameType) are preserved.
218:   }
219: 
220:   // ── Level Progression ──
221: 
222:   Future<List<GameLevelModel>> getLevels() async {
223:     var levels = _progressRepository.getLevels();
224:     if (levels.isEmpty) {
225:       levels = await _progressRepository.loadLevelsFromJson();
226:       await _progressRepository.saveLevels(levels);
227:     }
228:     return levels;
229:   }
230: 
231:   Future<void> completeLevel(String levelId, int stars) async {
232:     await _progressRepository.completeLevel(levelId, stars);
233:     await _progressRepository.advanceLevel();
234:   }
235: 
236:   GameLevelModel? getNextUnlockedLevel() {
237:     final levels = _progressRepository.getLevels();
238:     for (final level in levels) {
239:       if (level.unlocked && !level.completed) {
240:         return level;
241:       }
242:     }
243:     return levels.isNotEmpty ? levels.first : null;
244:   }
245: 
246:   // ── Game Mode Management ──
247: 
248:   bool isModeUnlocked(GameMode mode) {
249:     final progress = _progressRepository.getProgress();
250:     if (progress == null) return mode == GameMode.practice;
251:     return progress.unlockedModes.contains(mode.name);
252:   }
253: 
254:   Future<void> unlockMode(GameMode mode) async {
255:     await _progressRepository.unlockMode(mode.name);
256:   }
257: 
258:   // ── Question Generation ──
259: 
260:   List<GameQuestionModel> generatePracticeSet({
261:     required List<GameQuestionModel> allQuestions,
262:     int count = 10,
263:   }) {
264:     final shuffled = List<GameQuestionModel>.from(allQuestions)..shuffle();
265:     return shuffled.take(count).toList();
266:   }
267: 
268:   List<GameQuestionModel> generateChallengeSet({
269:     required List<GameQuestionModel> allQuestions,
270:     int count = 20,
271:     String? difficulty,
272:   }) {
273:     var pool = allQuestions;
274:     if (difficulty != null) {
275:       pool = pool.where((q) => q.difficulty == difficulty).toList();
276:     }
277:     final shuffled = List<GameQuestionModel>.from(pool)..shuffle();
278:     return shuffled.take(count).toList();
279:   }
