313:   /// Get the Monday of current week as "YYYY-MM-DD" string
314:   static String _getCurrentWeekStart() {
315:     final now = DateTime.now();
316:     final daysSinceMonday = now.weekday - 1;
317:     final monday = now.subtract(Duration(days: daysSinceMonday));
318:     return '${monday.year}-${monday.month.toString().padLeft(2, '0')}-${monday.day.toString().padLeft(2, '0')}';
319:   }
