321:   /// Save weekly activity map to game_progress box (for Firebase sync)
322:   static Future<void> _saveWeeklyActivityToGameProgress(Map<String, dynamic> activity) async {
323:     if (!Hive.isBoxOpen(_gameProgressBox)) return;
324:     final box = Hive.box(_gameProgressBox);
325:     final raw = box.get('user_progress');
326:     if (raw == null) return;
327:     try {
328:       final progress = GameProgressModel.fromMap(
329:         Map<String, dynamic>.from(raw as Map),
330:         '',
331:       );
332:       final updated = progress.copyWith(
333:         weeklyActivity: activity.map((k, v) => MapEntry(k, v == true)),
334:         weeklyActivityWeekStart: _getCurrentWeekStart(),
335:       );
336:       await box.put('user_progress', updated.toMap());
337:     } catch (_) {
338:       // Silently ignore parse errors
339:     }
340:   }
341: 
342:   /// Restore weekly activity from game_progress box to settings box.
343:   /// Call this after syncing progress from Firestore to Hive.
344:   static void restoreWeeklyActivityFromProgress() {
345:     if (!Hive.isBoxOpen(_gameProgressBox)) return;
346:     final box = Hive.box(_gameProgressBox);
347:     final raw = box.get('user_progress');
348:     if (raw == null) return;
349: 
350:     try {
351:       final progress = GameProgressModel.fromMap(
352:         Map<String, dynamic>.from(raw as Map),
353:         '',
354:       );
355: 
356:       // Only restore if the stored week matches the current week
357:       if (progress.weeklyActivityWeekStart == _getCurrentWeekStart()) {
358:         final restoredMap = progress.weeklyActivity
359:             .map((k, v) => MapEntry(k, v as dynamic));
360:         _settings.put('weekly_activity', restoredMap);
361:       }
362:     } catch (_) {
363:       // Silently ignore parse errors
364:     }
365:   }
