27: 
28:     // Already opened today → skip notification
29:     if (lastOpenDate.year == now.year &&
30:         lastOpenDate.month == now.month &&
31:         lastOpenDate.day == now.day) {
32:       return const InactivityResult(shouldNotify: false);
