13: class ReEngagementService {
14:   /// Checks whether the user has been inactive and should receive a
15:   /// motivational notification. Uses [HiveService] to read the last
16:   /// app open date. Returns [InactivityResult] with the number of
17:   /// inactive days and whether a notification should be sent.
18:   static Future<InactivityResult> checkInactivity() async {
19:     final lastOpenDate = HiveService.getLastAppOpenDate();
20:     final now = DateTime.now();
21: 
22:     // If no record exists yet (first install), treat as active today
23:     if (lastOpenDate == null) {
24:       await HiveService.setLastAppOpenDate(now);
25:       return const InactivityResult(shouldNotify: false);
26:     }
27: 
28:     // Already opened today → skip notification
29:     if (lastOpenDate.year == now.year &&
30:         lastOpenDate.month == now.month &&
31:         lastOpenDate.day == now.day) {
32:       return const InactivityResult(shouldNotify: false);
33:     }
34: 
35:     // Re-engagement toggle off → skip
36:     if (!HiveService.isReEngagementEnabled()) {
37:       return InactivityResult(shouldNotify: false);
38:     }
39: 
40:     final daysInactive = now.difference(lastOpenDate).inDays;
41: 
42:     return InactivityResult(
43:       daysInactive: daysInactive,
44:       shouldNotify: daysInactive >= 1,
45:     );
46:   }
47: 
48:   /// Returns a motivational message tailored to how many days the user
49:   /// has been inactive. [userName] is optional — if empty, uses a generic
50:   /// greeting.
