4: /// Service to fetch and cache remote app configuration from Firestore.
5: ///
6: /// The config is stored at `Config/app_settings` and allows:
7: /// - Feature toggle control
8: /// - Force update announcements
9: /// - Maintenance mode
10: /// - Gameplay settings
11: class RemoteConfigService {
12:   static final FirebaseFirestore _firestore = FirebaseFirestore.instance;
13:   static AppConfig? _cachedConfig;
14:   static DateTime? _lastFetchTime;
15:   static const Duration _cacheDuration = Duration(minutes: 5);
16: 
17:   /// Reference to the config document
18:   static DocumentReference get _configRef =>
19:       _firestore.collection('Config').doc('app_settings');
20: 
21:   /// Fetches the app config from Firestore with caching.
22:   ///
23:   /// Returns cached config if it was fetched within [_cacheDuration].
24:   /// Otherwise fetches fresh data from Firestore.
25:   static Future<AppConfig> getConfig() async {
26:     // Return cached config if still valid
27:     if (_cachedConfig != null &&
28:         _lastFetchTime != null &&
29:         DateTime.now().difference(_lastFetchTime!) < _cacheDuration) {
30:       return _cachedConfig!;
31:     }
32: 
33:     try {
34:       final doc = await _configRef.get();
35:       if (doc.exists) {
36:         _cachedConfig = AppConfig.fromSnapshot(doc);
37:       } else {
38:         // If document doesn't exist, create it with defaults
39:         _cachedConfig = const AppConfig();
40:         await _configRef.set(_cachedConfig!.toMap());
41:       }
42:       _lastFetchTime = DateTime.now();
43:       return _cachedConfig!;
44:     } catch (e) {
45:       // Return cached config or defaults on error
46:       if (_cachedConfig != null) return _cachedConfig!;
47:       return const AppConfig();
48:     }
49:   }
50: 
51:   /// Checks if a specific feature is enabled.
52:   ///
53:   /// Features: aiTeacher, games, homework, sentenceAnalyzer, speaking, listening
54:   static Future<bool> isFeatureEnabled(String feature) async {
55:     final config = await getConfig();
56:     return config.featureToggles.isEnabled(feature);
57:   }
58: 
59:   /// Checks if maintenance mode is active.
60:   static Future<bool> isMaintenanceMode() async {
61:     final config = await getConfig();
62:     return config.maintenanceMode.enabled;
63:   }
64: 
65:   /// Returns force update info if force update is enabled.
66:   static Future<ForceUpdateInfo?> getForceUpdateInfo() async {
67:     final config = await getConfig();
68:     if (config.forceUpdate.enabled) {
69:       return config.forceUpdate;
70:     }
71:     return null;
72:   }
73: 
74:   /// Returns the streak freeze cost from gameplay settings.
75:   static Future<int> getStreakFreezeCost() async {
76:     final config = await getConfig();
77:     return config.gameplay.streakFreezeCost;
78:   }
79: 
80:   /// Returns the daily goal XP from gameplay settings.
81:   static Future<int> getDailyGoalXP() async {
82:     final config = await getConfig();
83:     return config.gameplay.dailyGoalXP;
84:   }
85: 
86:   /// Returns the max streak freezes from gameplay settings.
87:   static Future<int> getMaxStreakFreezes() async {
88:     final config = await getConfig();
89:     return config.gameplay.maxStreakFreezes;
90:   }
91: 
92:   /// Returns the cost to unlock a mock test with coins.
93:   static Future<int> getMockTestCoinPrice() async {
94:     final config = await getConfig();
95:     return config.gameplay.mockTestCoinPrice;
96:   }
97: 
98:   /// Returns whether ad-based mock test unlock is enabled.
99:   static Future<bool> isMockTestAdUnlockEnabled() async {
100:     final config = await getConfig();
101:     return config.gameplay.mockTestAdUnlockEnabled;
102:   }
103: 
104:   /// Returns how many hours an ad-based unlock lasts.
105:   static Future<int> getMockTestAdUnlockDurationHours() async {
106:     final config = await getConfig();
