108:   }
109: 
110:   /// Returns the maintenance message if maintenance mode is active.
111:   static Future<String?> getMaintenanceMessage() async {
112:     final config = await getConfig();
113:     if (config.maintenanceMode.enabled) {
114:       return config.maintenanceMode.message;
115:     }
116:     return null;
117:   }
118: 
119:   /// Updates the entire config document in Firestore.
120:   ///
121:   /// This is an admin operation. Pass the full updated map.
122:   static Future<void> updateConfig(Map<String, dynamic> updates) async {
123:     await _configRef.set(updates, SetOptions(merge: true));
124:     // Invalidate cache so next read fetches fresh data
125:     _cachedConfig = null;
126:     _lastFetchTime = null;
