32: 
33:   /// Loads questions from all per-tense files and merges them.
34:   /// Falls back to the legacy single-file path if no per-tense files
35:   /// contain questions.
36:   Future<List<GameQuestionModel>> loadFromJson() async {
37:     final List<GameQuestionModel> all = [];
38: 
39:     for (final path in _tenseQuestionFiles) {
40:       try {
41:         final jsonString = await rootBundle.loadString(path);
42:         final data = json.decode(jsonString) as Map<String, dynamic>;
43:         final questionsList = data['questions'] as List<dynamic>? ?? [];
44:         all.addAll(
45:           questionsList.map(
46:             (q) => GameQuestionModel.fromMap(q as Map<String, dynamic>, ''),
47:           ),
48:         );
49:       } catch (_) {
50:         // File missing or invalid — skip silently and continue.
51:       }
52:     }
53: 
54:     // Legacy fallback: if per-tense files yielded nothing, try the old path.
55:     if (all.isEmpty) {
56:       try {
57:         final jsonString = await rootBundle.loadString(_legacyJsonPath);
58:         final data = json.decode(jsonString) as Map<String, dynamic>;
59:         final questionsList = data['questions'] as List<dynamic>? ?? [];
60:         return questionsList
61:             .map((q) => GameQuestionModel.fromMap(q as Map<String, dynamic>, ''))
62:             .toList();
63:       } catch (_) {
64:         return [];
65:       }
66:     }
67: 
68:     return all;
69:   }
