71:   // ── Hive (Local Cache) ──
72: 
73:   Future<Box> _ensureBox() async {
74:     if (!Hive.isBoxOpen(_boxName)) {
75:       return await Hive.openBox(_boxName);
76:     }
77:     return Hive.box(_boxName);
78:   }
79: 
80:   Future<void> cacheQuestions(List<GameQuestionModel> questions) async {
81:     final box = await _ensureBox();
82:     final maps = questions.map((q) => q.toMap()).toList();
83:     await box.put(_questionsKey, maps);
84:   }
85: 
86:   List<GameQuestionModel> getCachedQuestions() {
87:     if (!Hive.isBoxOpen(_boxName)) return [];
88:     final box = Hive.box(_boxName);
89:     final raw = box.get(_questionsKey, defaultValue: <Map<String, dynamic>>[]) as List;
90:     return raw
91:         .map((e) => GameQuestionModel.fromMap(Map<String, dynamic>.from(e as Map), ''))
92:         .toList();
93:   }
94: 
95:   Future<void> clearCache() async {
96:     final box = await _ensureBox();
97:     await box.delete(_questionsKey);
98:   }
99: 
100:   // ── Firestore (Remote) ──
101: 
102:   Future<List<GameQuestionModel>> fetchFromFirestore() async {
103:     final snapshot = await FirebaseFirestore.instance
104:         .collection(_firestoreCollection)
105:         .get();
106:     return snapshot.docs
107:         .map((doc) => GameQuestionModel.fromMap(doc.data(), doc.id))
108:         .toList();
109:   }
110: 
111:   Future<void> uploadToFirestore(GameQuestionModel question) async {
112:     await FirebaseFirestore.instance
113:         .collection(_firestoreCollection)
114:         .doc(question.id)
115:         .set(question.toMap());
116:   }
117: 
118:   Future<void> batchUploadToFirestore(List<GameQuestionModel> questions) async {
119:     final batch = FirebaseFirestore.instance.batch();
120:     for (final question in questions) {
121:       final ref = FirebaseFirestore.instance
122:           .collection(_firestoreCollection)
123:           .doc(question.id);
124:       batch.set(ref, question.toMap());
125:     }
126:     await batch.commit();
127:   }
128: 
129:   Future<void> deleteFromFirestore(String questionId) async {
130:     await FirebaseFirestore.instance
131:         .collection(_firestoreCollection)
132:         .doc(questionId)
133:         .delete();
134:   }
135: 
136:   // ── Sync (JSON → Hive → Firestore) ──
137: 
138:   Future<void> syncFromJsonToHive() async {
139:     final questions = await loadFromJson();
140:     await cacheQuestions(questions);
141:   }
142: 
143:   Future<void> syncFromFirestoreToHive() async {
144:     final questions = await fetchFromFirestore();
145:     await cacheQuestions(questions);
146:   }
147: }

