16: /// Initializes all required services when WorkManager runs in a background
17: /// isolate (i.e., after the app has been killed). In that scenario [main] is
18: /// never called, so Firebase, Hive, and the notification plugin must be set
19: /// up before any task handler runs.
20: Future<void> _initializeBackgroundServices() async {
21:   try {
22:     // On some Android versions the background isolate may inherit the
23:     // Firebase app from the main isolate, causing a duplicate-app error.
24:     // Check both apps.isEmpty and catch duplicate-app gracefully.
25:     try {
26:       if (Firebase.apps.isEmpty) {
27:         await Firebase.initializeApp(
28:           options: DefaultFirebaseOptions.currentPlatform,
29:         );
30:       }
31:     } catch (e) {
32:       if (!e.toString().contains('[core/duplicate-app]')) {
33:         rethrow;
34:       }
35:       debugPrint('WorkManager: Firebase already initialized (duplicate-app ignored)');
36:     }
37:   } catch (e) {
38:     debugPrint('WorkManager: Firebase init failed — $e');
39:   }
40: 
41:   try {
42:     await HiveService.initialize();
43:   } catch (e) {
44:     debugPrint('WorkManager: Hive init failed — $e');
45:   }
46: 
