3: /// Utility to ensure no Firestore [Timestamp] objects leak into Hive storage.
4: /// Hive does not support [Timestamp] natively — all Timestamps must be
5: /// converted to [DateTime] or milliseconds-epoch [int] before writing.
6: class HiveSafe {
7:   /// Recursively converts any [Timestamp] values in a map to their
8:   /// milliseconds-since-epoch representation ([int]), so the entire map
9:   /// contains only types that Hive can serialize natively.
10:   static Map<String, dynamic> sanitizeMap(Map<String, dynamic> map) {
11:     final result = <String, dynamic>{};
12:     for (final entry in map.entries) {
13:       result[entry.key] = _sanitizeValue(entry.value);
14:     }
15:     return result;
16:   }
17: 
18:   /// Recursively converts any [Timestamp] values in a list to safe types.
19:   static List<dynamic> sanitizeList(List<dynamic> list) {
20:     return list.map((e) => _sanitizeValue(e)).toList();
21:   }
22: 
23:   static dynamic _sanitizeValue(dynamic value) {
24:     if (value is Timestamp) {
25:       return value.millisecondsSinceEpoch;
26:     }
27:     if (value is Map<String, dynamic>) {
28:       return sanitizeMap(value);
29:     }
30:     if (value is List<dynamic>) {
31:       return sanitizeList(value);
32:     }
33:     // For other types (int, double, bool, String, DateTime, null, etc.)
34:     // Hive supports them natively, so pass through.
35:     return value;
36:   }
37: }

