54: /// Entry point called by WorkManager for all background tasks.
55: /// Must be tagged with @pragma('vm:entry-point') so the Dart VM
56: /// keeps it during tree-shaking.
57: @pragma('vm:entry-point')
58: void workmanagerCallbackDispatcher() {
59:   Workmanager().executeTask((task, inputData) async {
