35:   /// Initializes OneSignal with the given [appId].
36:   ///
37:   /// Sets up notification click and receive listeners, requests permissions,
38:   /// and captures the push subscription ID for targeted messaging.
39:   Future<void> initialize(String appId) async {
40:     if (_initialized) return;
41: 
42:     _appId = appId;
43: 
44:     if (_appId.isEmpty || _appId == 'YOUR_ONESIGNAL_APP_ID') {
45:       debugPrint('OneSignal: Skipping init — no valid App ID configured.');
46:       return;
47:     }
48: 
49:     try {
50:       // Log level — mute in production builds
51:       OneSignal.Debug.setLogLevel(
52:         kReleaseMode ? OSLogLevel.warn : OSLogLevel.verbose,
53:       );
54: 
55:       OneSignal.initialize(_appId);
56: 
57:       // ── Foreground notification handler ──
58:       // OneSignal v5: if you call preventDefault(), the notification is HIDDEN.
59:       // We want to SAVE to history AND show the notification, so we do NOT
60:       // call preventDefault() — the OS shows it automatically after the listener.
61:       OneSignal.Notifications.addForegroundWillDisplayListener((event) {
62:         final notif = event.notification;
63:         _saveToHistory(notif);
64:         // Do NOT call preventDefault() — we want the notification to display
65:         // as a heads-up banner. The notification is delivered to system tray
66:         // even when the app is closed (via native Android OneSignal service).
67:       });
68: 
69:       // ── Notification tap handler ──
70:       OneSignal.Notifications.addClickListener((event) {
71:         final notif = event.notification;
72:         // Mark as read and navigate
73:         _handleNotificationOpened(notif);
74:       });
75: 
76:       // Request permission (iOS shows native prompt, Android 13+ shows prompt)
77:       await OneSignal.Notifications.requestPermission(true);
78: 
79:       // Capture the push subscription ID for potential server-side targeting
80:       final subscription = OneSignal.User.pushSubscription;
81:       _playerId = subscription.id;
82:       subscription.addObserver((state) {
83:         _playerId = state.current.id;
84:       });
85: 
86:       _initialized = true;
87:       debugPrint('OneSignal: initialized successfully (playerId: $_playerId)');
88:     } catch (e) {
89:       debugPrint('OneSignal: initialization failed — $e');
90:     }
91:   }
