116:   /// Saves a received OSNotification to the local Hive history.
117:   void _saveToHistory(OSNotification notification) {
118:     try {
119:       final additionalData = notification.additionalData ?? {};
120:       final title = notification.title ?? '';
121:       final body = notification.body ?? '';
122: 
123:       if (title.isEmpty && body.isEmpty) return;
124: 
